"""Boilerplate-specific SigningPartner instances for PKI test infrastructure.

Each instance bundles: PEM key, cert usage, and per-device certificate hex data.
"""

from pathlib import Path
from ledgered.devices import DeviceType  # type: ignore[import-untyped]
from ragger.pki import SigningPartner, CertificatePubKeyUsage

_KEYCHAIN_DIR = Path(__file__).parent / "keychain"

# pylint: disable=line-too-long
DYNAMIC_TOKEN_PARTNER = SigningPartner(
    pem_key_path=_KEYCHAIN_DIR / "dynamic_token.pem",
    cert_pub_key_usage=CertificatePubKeyUsage.COIN_META,
    certificates={
        DeviceType.NANOSP: "",  # noqa: E501
        DeviceType.NANOX:  "",  # noqa: E501
        DeviceType.STAX:   "",  # noqa: E501
        DeviceType.FLEX:   "",  # noqa: E501
        DeviceType.APEX_P: "",  # noqa: E501
    },
)
# pylint: enable=line-too-long
